const express = require('express');

const router = express.Router();

router.get('/', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

module.exports = router;

// Request logger middleware: logs method, path, status code, and response time.
module.exports = function logger(req, res, next) {
  const start = process.hrtime.bigint();

  res.on('finish', () => {
    const durationMs = Number(process.hrtime.bigint() - start) / 1e6;
    console.log(
      `${req.method} ${req.originalUrl || req.url} ${res.statusCode} ${durationMs.toFixed(2)}ms`
    );
  });

  next();
};

// Centralised error handler: formats all error responses consistently.
// eslint-disable-next-line no-unused-vars
module.exports = function errorHandler(err, req, res, next) {
  const status = err.status || err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  if (process.env.NODE_ENV !== 'test') {
    console.error(`[error] ${req.method} ${req.originalUrl || req.url} -> ${status}: ${message}`);
  }

  res.status(status).json({
    error: {
      status,
      message,
    },
  });
};

