// User-related endpoints.
// Keep the route handlers thin — error handling is centralised in
// middleware/errorHandler.js via `next(err)`.

const express = require('express');

const router = express.Router();

const USERS = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

router.get('/', (req, res) => {
  res.json(USERS);
});

module.exports = router;

// Request logger middleware.
// Logs method, path, status code, and response time (ms) for every request.
// Uses the `finish` event on the response so the status code is accurate
// regardless of which handler ultimately sends the response.

function logger(req, res, next) {
  const start = process.hrtime.bigint();

  res.on('finish', () => {
    const durationNs = process.hrtime.bigint() - start;
    const durationMs = Number(durationNs) / 1e6;
    // eslint-disable-next-line no-console
    console.log(
      `${req.method} ${req.originalUrl || req.url} ${res.statusCode} ${durationMs.toFixed(2)}ms`,
    );
  });

  next();
}

module.exports = logger;

// Centralised error handler.
// Formats every error response as a consistent JSON body:
//   { error: { status, message } }
// Honours `err.status` / `err.statusCode` when present, otherwise 500.

function errorHandler(err, req, res, next) {
  // If the response has already started streaming, delegate to the default
  // Express handler which will close the connection.
  if (res.headersSent) {
    return next(err);
  }

  const status = Number(err.status || err.statusCode) || 500;
  const message =
    status >= 500 && !err.expose
      ? 'Internal Server Error'
      : err.message || 'Error';

  // eslint-disable-next-line no-console
  if (status >= 500) console.error(err);

  res.status(status).json({
    error: {
      status,
      message,
    },
  });
}

module.exports = errorHandler;

